interface LazySwitchBannerProps {
  backgroundSessionName: string | null
  isAgentEnded: boolean
  onStop: () => void
}

function LazySwitchBanner({ backgroundSessionName, isAgentEnded, onStop }: LazySwitchBannerProps): React.ReactElement {
  return (
    <div className="flex items-center justify-between bg-blue-50 border-b border-blue-200 px-4 py-1.5">
      <div className="flex items-center gap-2">
        {isAgentEnded ? (
          <span className="text-xs text-gray-500">正在切换回当前会话...</span>
        ) : (
          <>
            <span className="relative flex h-2 w-2">
              <span className="absolute inline-flex h-full w-full animate-ping rounded-full bg-blue-400 opacity-75" />
              <span className="relative inline-flex h-2 w-2 rounded-full bg-blue-500" />
            </span>
            <span className="text-xs text-blue-700">
              Session &quot;{backgroundSessionName ?? ''}&quot; 后台运行中
            </span>
          </>
        )}
      </div>
      {!isAgentEnded && (
        <button
          onClick={onStop}
          className="rounded bg-red-600 px-2.5 py-0.5 text-xs font-medium text-white hover:bg-red-500"
        >
          Stop
        </button>
      )}
    </div>
  )
}

export default LazySwitchBanner

/**
 * useSessionCache — Manages per-session message caching for Lazy Session Switch.
 *
 * Decouples the "displayed session" (what the user sees) from the
 * "Pi-connected session" (which session the Pi worker is on).
 * When they differ, the displayed session is in read-only mode.
 *
 * Pi events are always written to the Pi-connected session's cache.
 * The UI is only refreshed when the displayed session matches the
 * Pi-connected session (or when the user explicitly switches).
 */
import { useState, useCallback, useRef } from 'react'
import type { ChatMessage, ContentBlock } from '../types/message'
import type { ForkPoint } from '../types/session'
import { convertPiMessagesToChatMessages, type TokenUsage } from '../utils/convert-messages'

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface SessionCache {
  sessionPath: string
  messages: ChatMessage[]
  isStreaming: boolean
  streamingMessageId: string | null
  tokenUsage: TokenUsage
  forkPoints: ForkPoint[]
  loadedAt: number

  // Pi streaming intermediate state — needed to resume receiving deltas
  // after switching away and back to a streaming session
  currentAssistantId: string | null
  currentContentBlocks: Map<number, ContentBlock>
  toolCallArgsBuffer: Map<number, string>
  pendingToolCallArgs: Map<string, Record<string, unknown>>
  countedResponseIds: Set<string>
}

interface UseSessionCacheReturn {
  // What the user is looking at
  displayedSessionPath: string | null
  // Messages for the displayed session
  displayedMessages: ChatMessage[]
  // Whether the displayed session is streaming
  isDisplayedStreaming: boolean
  // Token usage for the displayed session
  displayedTokenUsage: TokenUsage
  // Fork points for the displayed session
  displayedForkPoints: ForkPoint[]
  // Streaming message ID for the displayed session
  displayedStreamingMessageId: string | null

  // Get cache for a specific session
  getCache: (sessionPath: string) => SessionCache | undefined
  // Get or create cache for a session (loads from JSONL if not cached)
  getOrCreateCache: (sessionPath: string) => Promise<SessionCache>
  // Update a session's cache (used by usePiRpc to write streaming events)
  updateCache: (sessionPath: string, updater: (cache: SessionCache) => SessionCache) => void
  // Switch the displayed session (does NOT switch Pi connection)
  displaySession: (sessionPath: string) => Promise<void>
  // Clear a session's cache
  clearCache: (sessionPath: string) => void
  // Mark a session as streaming / not streaming
  setCacheStreaming: (sessionPath: string, isStreaming: boolean, streamingMessageId: string | null) => void
  // Refresh displayed messages from cache (after cache updates)
  refreshDisplayedMessages: () => void

  updatePiConnectedMessages: (piConnectedPath: string, updater: (prev: ChatMessage[]) => ChatMessage[]) => void
  updatePiConnectedTokenUsage: (piConnectedPath: string, updater: (prev: TokenUsage) => TokenUsage) => void
  setPiConnectedStreaming: (piConnectedPath: string, isStreaming: boolean, streamingMessageId: string | null) => void
  updatePiConnectedForkPoints: (piConnectedPath: string, forkPoints: ForkPoint[]) => void
}

// ---------------------------------------------------------------------------
// Initial values
// ---------------------------------------------------------------------------

const INITIAL_TOKEN_USAGE: TokenUsage = {
  inputTokens: 0,
  outputTokens: 0,
  cacheReadTokens: 0,
  cacheWriteTokens: 0,
  totalTokens: 0,
  totalCost: 0,
  contextWindowSize: 200000,
}

function createEmptyCache(sessionPath: string): SessionCache {
  return {
    sessionPath,
    messages: [],
    isStreaming: false,
    streamingMessageId: null,
    tokenUsage: { ...INITIAL_TOKEN_USAGE },
    forkPoints: [],
    loadedAt: 0,
    currentAssistantId: null,
    currentContentBlocks: new Map(),
    toolCallArgsBuffer: new Map(),
    pendingToolCallArgs: new Map(),
    countedResponseIds: new Set(),
  }
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useSessionCache(): UseSessionCacheReturn {
  const cacheMap = useRef<Map<string, SessionCache>>(new Map())

  const [displayedSessionPath, setDisplayedSessionPath] = useState<string | null>(null)
  const [displayedMessages, setDisplayedMessages] = useState<ChatMessage[]>([])
  const [displayedTokenUsage, setDisplayedTokenUsage] = useState<TokenUsage>({ ...INITIAL_TOKEN_USAGE })
  const [displayedForkPoints, setDisplayedForkPoints] = useState<ForkPoint[]>([])
  const [isDisplayedStreaming, setIsDisplayedStreaming] = useState(false)
  const [displayedStreamingMessageId, setDisplayedStreamingMessageId] = useState<string | null>(null)

  // Use a ref for displayedSessionPath to avoid circular dep chains
  // (callbacks that read displayedSessionPath also set it via setDisplayedSessionPath)
  const displayedSessionPathRef = useRef<string | null>(null)

  const syncDisplayedFromCache = useCallback((sessionPath: string | null) => {
    if (!sessionPath) {
      setDisplayedMessages([])
      setDisplayedTokenUsage({ ...INITIAL_TOKEN_USAGE })
      setDisplayedForkPoints([])
      setIsDisplayedStreaming(false)
      setDisplayedStreamingMessageId(null)
      return
    }
    const cache = cacheMap.current.get(sessionPath)
    if (cache) {
      setDisplayedMessages(cache.messages)
      setDisplayedTokenUsage(cache.tokenUsage)
      setDisplayedForkPoints(cache.forkPoints)
      setIsDisplayedStreaming(cache.isStreaming)
      setDisplayedStreamingMessageId(cache.streamingMessageId)
    }
  }, [])

  const getCache = useCallback((sessionPath: string): SessionCache | undefined => {
    return cacheMap.current.get(sessionPath)
  }, [])

  const getOrCreateCache = useCallback(async (sessionPath: string): Promise<SessionCache> => {
    const existing = cacheMap.current.get(sessionPath)
    if (existing) return existing

    // Load from JSONL via IPC
    let cache: SessionCache = createEmptyCache(sessionPath)
    try {
      type ApiWithGetMessagesForSession = typeof window.api & {
        getMessagesForSession: (path: string) => Promise<unknown[]>
      }
      const api = window.api as ApiWithGetMessagesForSession
      const piMessages = await api.getMessagesForSession(sessionPath)

      if (Array.isArray(piMessages) && piMessages.length > 0) {
        const result = convertPiMessagesToChatMessages(piMessages)
        cache = {
          ...cache,
          messages: result.messages,
          tokenUsage: result.tokenUsage,
          loadedAt: Date.now(),
          countedResponseIds: new Set(result.responseIds),
        }
      }
    } catch {
      // JSONL read failed — show empty state
    }

    cacheMap.current.set(sessionPath, cache)
    return cache
  }, [])

  const updateCache = useCallback((sessionPath: string, updater: (cache: SessionCache) => SessionCache) => {
    const existing = cacheMap.current.get(sessionPath)
    if (!existing) return
    const updated = updater(existing)
    cacheMap.current.set(sessionPath, updated)

    // If this is the displayed session, sync UI
    if (sessionPath === displayedSessionPathRef.current) {
      setDisplayedMessages(updated.messages)
      setDisplayedTokenUsage(updated.tokenUsage)
      setDisplayedForkPoints(updated.forkPoints)
      setIsDisplayedStreaming(updated.isStreaming)
      setDisplayedStreamingMessageId(updated.streamingMessageId)
    }
  }, [])

  const displaySession = useCallback(async (sessionPath: string) => {
    displayedSessionPathRef.current = sessionPath
    setDisplayedSessionPath(sessionPath)
    const cache = await getOrCreateCache(sessionPath)
    if (displayedSessionPathRef.current !== sessionPath) return
    syncDisplayedFromCache(sessionPath)

    try {
      type ApiWithForkPoints = typeof window.api & {
        getForkPoints: (path: string) => Promise<ForkPoint[]>
      }
      const api = window.api as ApiWithForkPoints
      const points = await api.getForkPoints(sessionPath)
      if (displayedSessionPathRef.current !== sessionPath) return
      const updated: SessionCache = { ...cache, forkPoints: points }
      cacheMap.current.set(sessionPath, updated)
      if (sessionPath === displayedSessionPathRef.current) {
        setDisplayedForkPoints(points)
      }
    } catch {
      // ignore
    }
  }, [getOrCreateCache, syncDisplayedFromCache])

  const clearCache = useCallback((sessionPath: string) => {
    cacheMap.current.delete(sessionPath)
    if (sessionPath === displayedSessionPathRef.current) {
      syncDisplayedFromCache(displayedSessionPathRef.current)
    }
  }, [syncDisplayedFromCache])

  const setCacheStreaming = useCallback((sessionPath: string, isStreaming: boolean, streamingMessageId: string | null) => {
    const cache = cacheMap.current.get(sessionPath)
    if (!cache) return
    const updated = { ...cache, isStreaming, streamingMessageId }
    cacheMap.current.set(sessionPath, updated)
    if (sessionPath === displayedSessionPathRef.current) {
      setIsDisplayedStreaming(isStreaming)
      setDisplayedStreamingMessageId(streamingMessageId)
    }
  }, [])

  const refreshDisplayedMessages = useCallback(() => {
    syncDisplayedFromCache(displayedSessionPathRef.current)
  }, [syncDisplayedFromCache])

  const updatePiConnectedMessages = useCallback((piConnectedPath: string, updater: (prev: ChatMessage[]) => ChatMessage[]) => {
    const cache = cacheMap.current.get(piConnectedPath)
    if (!cache) return
    const updatedMessages = updater(cache.messages)
    const updated = { ...cache, messages: updatedMessages }
    cacheMap.current.set(piConnectedPath, updated)

    if (piConnectedPath === displayedSessionPathRef.current) {
      setDisplayedMessages(updatedMessages)
    }
  }, [])

  const updatePiConnectedTokenUsage = useCallback((piConnectedPath: string, updater: (prev: TokenUsage) => TokenUsage) => {
    const cache = cacheMap.current.get(piConnectedPath)
    if (!cache) return
    const updatedTokenUsage = updater(cache.tokenUsage)
    const updated = { ...cache, tokenUsage: updatedTokenUsage }
    cacheMap.current.set(piConnectedPath, updated)

    if (piConnectedPath === displayedSessionPathRef.current) {
      setDisplayedTokenUsage(updatedTokenUsage)
    }
  }, [])

  const setPiConnectedStreaming = useCallback((piConnectedPath: string, isStreaming: boolean, streamingMessageId: string | null) => {
    const cache = cacheMap.current.get(piConnectedPath)
    if (!cache) return
    const updated = { ...cache, isStreaming, streamingMessageId }
    cacheMap.current.set(piConnectedPath, updated)

    if (piConnectedPath === displayedSessionPathRef.current) {
      setIsDisplayedStreaming(isStreaming)
      setDisplayedStreamingMessageId(streamingMessageId)
    }
  }, [])

  const updatePiConnectedForkPoints = useCallback((piConnectedPath: string, forkPoints: ForkPoint[]) => {
    const cache = cacheMap.current.get(piConnectedPath)
    if (!cache) return
    const updated = { ...cache, forkPoints }
    cacheMap.current.set(piConnectedPath, updated)

    if (piConnectedPath === displayedSessionPathRef.current) {
      setDisplayedForkPoints(forkPoints)
    }
  }, [])

  return {
    displayedSessionPath,
    displayedMessages,
    isDisplayedStreaming,
    displayedTokenUsage,
    displayedForkPoints,
    displayedStreamingMessageId,
    getCache,
    getOrCreateCache,
    updateCache,
    displaySession,
    clearCache,
    setCacheStreaming,
    refreshDisplayedMessages,
    updatePiConnectedMessages,
    updatePiConnectedTokenUsage,
    setPiConnectedStreaming,
    updatePiConnectedForkPoints,
  }
}

import { readdirSync, readFileSync, existsSync, appendFileSync, unlinkSync, rmSync, mkdirSync } from 'fs'
import { join, dirname, resolve } from 'path'
import type {
  SessionInfo,
  SessionListResult,
  SessionFileHeader,
  ProjectSessionTree,
  SessionTreeNode,
  ForkPoint
} from '../renderer/src/types/session'

export function getSessionDir(cwd?: string): string {
  const projectRoot = cwd ?? process.cwd()
  const resolvedCwd = resolve(projectRoot)
  const agentDir = join(resolvedCwd, '.xi')
  const safePath = `--${resolvedCwd.replace(/^[/\\]/, '').replace(/[/\\:]/g, '-')}--`
  const sessionDir = join(agentDir, 'sessions', safePath)
  if (!existsSync(sessionDir)) {
    mkdirSync(sessionDir, { recursive: true })
  }
  return sessionDir
}


export function parseSessionFile(filePath: string): SessionInfo | null {
  try {
    const content = readFileSync(filePath, 'utf-8')
    const lines = content.split('\n').filter((line) => line.trim().length > 0)
    if (lines.length === 0) return null

    let header: SessionFileHeader
    try {
      header = JSON.parse(lines[0]) as SessionFileHeader
    } catch {
      return null
    }

    if (header.type !== 'session') return null

    let messageCount = 0
    let name: string | null = null
    let status: 'active' | 'completed' | null = null

    for (let i = 1; i < lines.length; i++) {
      try {
        const entry = JSON.parse(lines[i]) as Record<string, unknown>
        if (entry.type === 'message') {
          const message = entry.message as Record<string, unknown> | undefined
          if (message && message.role === 'user') {
            messageCount++
          }
        } else if (entry.type === 'session_info') {
          if (typeof entry.name === 'string') {
            name = entry.name
          }
          if (entry.status === 'active' || entry.status === 'completed') {
            status = entry.status
          }
        }
      } catch {
        continue
      }
    }

    return {
      filePath,
      sessionId: header.id,
      name,
      status,
      createdAt: header.timestamp,
      cwd: header.cwd,
      parentSessionPath: header.parentSession ?? null,
      messageCount,
      isMain: false
    }
  } catch {
    return null
  }
}

export function findMainSession(cwd: string, sessionDir?: string): SessionInfo | null {
  const dir = sessionDir ?? getSessionDir()
  if (!existsSync(dir)) return null

  const sessionFiles = readdirSync(dir)
    .filter((name) => name.endsWith('.jsonl'))
    .map((name) => join(dir, name))

  for (const filePath of sessionFiles) {
    const info = parseSessionFile(filePath)
    if (info && info.cwd === cwd && info.name === 'main') {
      return info
    }
  }

  const candidates: SessionInfo[] = []
  for (const filePath of sessionFiles) {
    const info = parseSessionFile(filePath)
    if (info && info.cwd === cwd) {
      candidates.push(info)
    }
  }
  if (candidates.length > 0) {
    candidates.sort((a, b) => a.createdAt.localeCompare(b.createdAt))
    return candidates[0]
  }

  return null
}

export function listSessions(_currentSessionPath?: string, sessionDir?: string): SessionListResult {
  const sessionDirPath = sessionDir ?? getSessionDir()
  if (!existsSync(sessionDirPath)) {
    return { projects: [] }
  }

  let sessionFiles: string[]
  try {
    sessionFiles = readdirSync(sessionDirPath)
      .filter((name) => name.endsWith('.jsonl'))
      .map((name) => join(sessionDirPath, name))
  } catch {
    return { projects: [] }
  }

  const sessions: SessionInfo[] = []
  for (const filePath of sessionFiles) {
    const info = parseSessionFile(filePath)
    if (info) sessions.push(info)
  }

  if (sessions.length === 0) {
    return { projects: [] }
  }

  sessions.sort((a, b) => a.createdAt.localeCompare(b.createdAt))

  const namedMain = sessions.find((s) => s.name === 'main')
  if (namedMain) {
    namedMain.isMain = true
  } else if (sessions.length > 0) {
    sessions[0].isMain = true
  }

  const cwd = sessions[0].cwd
  const tree = buildSessionTree(sessions)
  const encodedDir = sessionDirPath.split('/').pop() ?? ''

  const projects: ProjectSessionTree[] = [{
    projectPath: cwd,
    encodedDir,
    root: tree,
    allSessions: sessions
  }]

  return { projects }
}

export function buildSessionTree(sessions: SessionInfo[]): SessionTreeNode | null {
  if (sessions.length === 0) return null

  const nodeMap = new Map<string, SessionTreeNode>()
  const parentedNodes = new Set<string>()

  for (const session of sessions) {
    nodeMap.set(session.filePath, { session, children: [] })
  }

  for (const session of sessions) {
    if (session.parentSessionPath && nodeMap.has(session.parentSessionPath)) {
      const parent = nodeMap.get(session.parentSessionPath)!
      const node = nodeMap.get(session.filePath)!
      parent.children.push(node)
      parentedNodes.add(session.filePath)
    }
  }

  let root: SessionTreeNode | null = null

  const mainSession = sessions.find((s) => s.isMain)
  if (mainSession) {
    root = nodeMap.get(mainSession.filePath) ?? null
  }

  if (!root) {
    const orphan = sessions.find((s) => !parentedNodes.has(s.filePath))
    if (orphan) {
      root = nodeMap.get(orphan.filePath) ?? null
    }
  }

  if (!root && sessions.length > 0) {
    root = nodeMap.get(sessions[0].filePath) ?? null
  }

  if (root) {
    for (const session of sessions) {
      if (session.filePath === root.session.filePath) continue
      if (parentedNodes.has(session.filePath)) continue
      const node = nodeMap.get(session.filePath)!
      root.children.push(node)
    }
  }

  return root
}

export function nameSession(sessionPath: string, name: string, _cwd?: string, _parentSessionPath?: string): boolean {
  try {
    // Only append session_info if the file already exists on disk.
    // For new sessions, the Pi worker's flush_session command handles
    // creating the file with the correct header (including parentSession).
    // Creating the file here would break Pi's lazy-flush mechanism
    // (Pi uses openSync with 'wx' flag which fails if file exists).
    if (!existsSync(sessionPath)) {
      return true
    }

    const entry = JSON.stringify({
      type: 'session_info',
      name,
    })
    appendFileSync(sessionPath, entry + '\n')
    return true
  } catch {
    return false
  }
}

export function deleteSession(sessionPath: string, sessionDir?: string): boolean {
  if (!existsSync(sessionPath)) return false

  try {
    unlinkSync(sessionPath)

    const dir = dirname(sessionPath)
    const remaining = readdirSync(dir).filter((name) => name.endsWith('.jsonl'))
    if (remaining.length === 0) {
      rmSync(dir, { recursive: true })
    }

    return true
  } catch {
    return false
  }
}

export function addForkPoint(sessionPath: string, entryId: string, childName: string): boolean {
  if (!existsSync(sessionPath)) return false

  try {
    const entry = JSON.stringify({
      type: 'fork_point',
      entryId,
      childName,
    })
    appendFileSync(sessionPath, entry + '\n')
    return true
  } catch {
    return false
  }
}

export function setSessionStatus(sessionPath: string, status: 'active' | 'completed'): boolean {
  if (!existsSync(sessionPath)) return false

  try {
    const entry = JSON.stringify({
      type: 'session_info',
      status,
    })
    appendFileSync(sessionPath, entry + '\n')
    return true
  } catch {
    return false
  }
}

/**
 * Parse a session JSONL file and return all messages in Pi's raw format.
 * This is the same format returned by the `get_messages` RPC, so the
 * renderer can reuse its existing loadHistory conversion logic.
 *
 * This is a pure file read — no Pi worker involved, no session switching.
 * Safe for Lazy Switch: when the Pi worker is connected to session A,
 * calling this for session B reads B's JSONL directly from disk.
 * Since Pi persists messages synchronously on `message_end`, and B is
 * not streaming (Pi only has one active session), the JSONL is always
 * complete and consistent.
 */
export function parseSessionMessages(filePath: string): unknown[] {
  if (!existsSync(filePath)) return []

  try {
    const content = readFileSync(filePath, 'utf-8')
    const lines = content.split('\n').filter((line) => line.trim().length > 0)
    if (lines.length === 0) return []

    const messages: unknown[] = []

    for (const line of lines) {
      try {
        const entry = JSON.parse(line) as Record<string, unknown>
        if (entry.type === 'message' && entry.message) {
          const msg = { ...(entry.message as Record<string, unknown>) }
          // Attach the entry id as the message id if not present
          // (matches pi-worker's get_messages behavior)
          if (!msg.id && typeof entry.id === 'string') {
            msg.id = entry.id
          }
          messages.push(msg)
        }
      } catch {
        continue
      }
    }

    return messages
  } catch {
    return []
  }
}

export function getForkPoints(sessionPath: string): ForkPoint[] {
  if (!existsSync(sessionPath)) return []

  const forkPoints: ForkPoint[] = []

  try {
    const content = readFileSync(sessionPath, 'utf-8')
    const lines = content.split('\n').filter((line) => line.trim().length > 0)

    for (let i = 1; i < lines.length; i++) {
      try {
        const entry = JSON.parse(lines[i]) as Record<string, unknown>
        if (entry.type === 'fork_point' && typeof entry.entryId === 'string') {
          forkPoints.push({
            entryId: entry.entryId,
            childName: typeof entry.childName === 'string' ? entry.childName : '',
          })
        }
      } catch {
        continue
      }
    }
  } catch {
    return []
  }

  return forkPoints
}

import { useEffect, useState, useCallback, useRef, useMemo } from 'react'
import { usePiRpc, type UsePiRpcOptions } from './hooks/usePiRpc'
import { useSessionManager } from './hooks/useSessionManager'
import { useSessionCache } from './hooks/useSessionCache'
import ChatView from './components/ChatView'
import InputBar from './components/InputBar'
import SessionSidebar from './components/SessionSidebar'
import LazySwitchBanner from './components/LazySwitchBanner'
import { TokenUsageRing } from './components/TokenUsageRing'
import type { ViewMode } from './utils/compact-view'
import type { ChatMessage } from './types/message'
import type { ForkPoint } from './types/session'
import type { TokenUsage } from './utils/convert-messages'

function getDisplayName(session: { name: string | null; createdAt: string }): string {
  if (session.name) return session.name
  const d = new Date(session.createdAt)
  const month = d.toLocaleString('en', { month: 'short' })
  const day = d.getDate()
  const hh = String(d.getHours()).padStart(2, '0')
  const mm = String(d.getMinutes()).padStart(2, '0')
  return `${month} ${day} ${hh}:${mm}`
}

function App(): React.ReactElement {
  const [piConnectedPath, setPiConnectedPathState] = useState<string | null>(null)
  const piConnectedPathRef = useRef<string | null>(null)

  // Updates both React state AND the ref synchronously so that
  // async callbacks (loadHistory, Pi event handlers) reading
  // piConnectedPathRef.current see the new value without waiting for re-render.
  const setPiConnectedPath = useCallback((path: string | null) => {
    piConnectedPathRef.current = path
    setPiConnectedPathState(path)
  }, [])

  const [isAgentEnding, setIsAgentEnding] = useState(false)
  const sessionCache = useSessionCache()
  const {
    displaySession, getCache, clearCache, getOrCreateCache,
    updatePiConnectedMessages, updatePiConnectedTokenUsage,
    setPiConnectedStreaming, updatePiConnectedForkPoints,
  } = sessionCache

  // Refs for stable access inside callbacks — avoids putting the
  // sessionCache object (which changes identity every render) into deps.
  const getCacheRef = useRef(getCache)
  getCacheRef.current = getCache
  const getOrCreateCacheRef = useRef(getOrCreateCache)
  getOrCreateCacheRef.current = getOrCreateCache
  const displaySessionRef = useRef(displaySession)
  displaySessionRef.current = displaySession

  // Mirror sessionCache display state into refs so callbacks can read
  // current values without re-creating on every change.
  const displayedSessionPathRef = useRef(sessionCache.displayedSessionPath)
  displayedSessionPathRef.current = sessionCache.displayedSessionPath
  const isDisplayedStreamingRef = useRef(sessionCache.isDisplayedStreaming)
  isDisplayedStreamingRef.current = sessionCache.isDisplayedStreaming

  const piRpcOptions: UsePiRpcOptions = useMemo(() => ({
    onMessagesUpdate: (updater: (prev: ChatMessage[]) => ChatMessage[]) => {
      const path = piConnectedPathRef.current
      if (path) updatePiConnectedMessages(path, updater)
    },
    onTokenUsageUpdate: (updater: (prev: TokenUsage) => TokenUsage) => {
      const path = piConnectedPathRef.current
      if (path) updatePiConnectedTokenUsage(path, updater)
    },
    onStreamingChange: (isStreaming: boolean, streamingMessageId: string | null) => {
      const path = piConnectedPathRef.current
      if (path) setPiConnectedStreaming(path, isStreaming, streamingMessageId)
    },
    onForkPointsUpdate: (forkPoints: ForkPoint[]) => {
      const path = piConnectedPathRef.current
      if (path) updatePiConnectedForkPoints(path, forkPoints)
    },
    piConnectedSessionPath: piConnectedPath,
  }), [updatePiConnectedMessages, updatePiConnectedTokenUsage, setPiConnectedStreaming, updatePiConnectedForkPoints, piConnectedPath])

  const { isConnected, sendPrompt, abort, pendingUiRequests, respondToUiRequest, clearMessages, loadHistory, loadForkPoints, setOnAgentEnd } = usePiRpc(piRpcOptions)
  const { sessions, currentSession, forkAtEntry, switchSession, newSession, renameSession, deleteSession, setSessionStatus, getForkMessages, clearSession, refresh } = useSessionManager(isConnected)

  const isLazySwitched = sessionCache.displayedSessionPath !== null && sessionCache.displayedSessionPath !== piConnectedPath
  const displayedMessages = sessionCache.displayedMessages
  const displayedTokenUsage = sessionCache.displayedTokenUsage
  const displayedForkPoints = sessionCache.displayedForkPoints
  const displayedStreaming = sessionCache.isDisplayedStreaming
  const displayedStreamingId = sessionCache.displayedStreamingMessageId

  const [error, setError] = useState<string | null>(null)
  const [sidebarCollapsed, setSidebarCollapsed] = useState(() => {
    const saved = localStorage.getItem('xi-sidebar-collapsed')
    return saved === 'true'
  })
  const [sidebarWidth, setSidebarWidth] = useState(() => {
    const saved = localStorage.getItem('xi-sidebar-width')
    const parsed = saved ? parseInt(saved, 10) : 260
    return Number.isNaN(parsed) ? 260 : Math.min(480, Math.max(180, parsed))
  })
  const [isResizing, setIsResizing] = useState(false)
  const sidebarWidthRef = useRef(sidebarWidth)
  sidebarWidthRef.current = sidebarWidth
  const resizeStartRef = useRef<{ startX: number; startWidth: number } | null>(null)

  useEffect(() => {
    if (!isResizing) return
    const handleMouseMove = (e: MouseEvent) => {
      if (!resizeStartRef.current) return
      const delta = e.clientX - resizeStartRef.current.startX
      const newWidth = Math.min(480, Math.max(180, resizeStartRef.current.startWidth + delta))
      setSidebarWidth(newWidth)
    }
    const handleMouseUp = () => {
      setIsResizing(false)
      resizeStartRef.current = null
      localStorage.setItem('xi-sidebar-width', String(sidebarWidthRef.current))
      document.body.style.cursor = ''
      document.body.style.userSelect = ''
    }
    document.body.style.cursor = 'col-resize'
    document.body.style.userSelect = 'none'
    window.addEventListener('mousemove', handleMouseMove)
    window.addEventListener('mouseup', handleMouseUp)
    return () => {
      window.removeEventListener('mousemove', handleMouseMove)
      window.removeEventListener('mouseup', handleMouseUp)
    }
  }, [isResizing])

  const handleResizeStart = useCallback((e: React.MouseEvent) => {
    e.preventDefault()
    setIsResizing(true)
    resizeStartRef.current = { startX: e.clientX, startWidth: sidebarWidth }
  }, [sidebarWidth])

  const [viewMode, setViewMode] = useState<ViewMode>(() => {
    const saved = localStorage.getItem('xi-view-mode') as ViewMode
    return saved === 'normal' || saved === 'turn' || saved === 'outline' ? saved : 'normal'
  })

  const activeSessionPath = isLazySwitched ? sessionCache.displayedSessionPath : (currentSession?.filePath ?? null)
  const activeSession = activeSessionPath
    ? sessions?.projects?.flatMap(p => p.allSessions).find(s => s.filePath === activeSessionPath)
    : currentSession

  const activeSessionName = activeSession ? getDisplayName(activeSession) : null

  const backgroundSessionName = (() => {
    if (!isLazySwitched || !piConnectedPath) return null
    const bgSession = sessions?.projects?.flatMap(p => p.allSessions).find(s => s.filePath === piConnectedPath)
    return bgSession ? getDisplayName(bgSession) : null
  })()

  async function handleConnect(): Promise<void> {
    setError(null)
    const result = await window.api.start()
    if (!result.ok && result.error) {
      setError(result.error)
    }
    refresh()
  }

  useEffect(() => {
    handleConnect()
  }, [])

  const isPiStreaming = useCallback((): boolean => {
    const path = piConnectedPathRef.current
    if (!path) return false
    return getCacheRef.current(path)?.isStreaming ?? false
  }, [])

  const handleSwitchSession = useCallback(async (sessionPath: string) => {
    const piStreaming = isPiStreaming() || isDisplayedStreamingRef.current
    if (piStreaming && piConnectedPathRef.current !== sessionPath) {
      await displaySessionRef.current(sessionPath)
      return
    }

    if (piConnectedPathRef.current === sessionPath) {
      if (displayedSessionPathRef.current !== sessionPath) {
        await displaySessionRef.current(sessionPath)
      }
      return
    }

    const prevPath = piConnectedPathRef.current
    await displaySessionRef.current(sessionPath)

    const result = await switchSession(sessionPath)
    if (result.success) {
      setPiConnectedPath(sessionPath)
      clearMessages()
      await loadHistory()
      await loadForkPoints(sessionPath)
      await refresh()
    } else {
      if (prevPath) await displaySessionRef.current(prevPath)
    }
  }, [switchSession, clearMessages, loadHistory, loadForkPoints, refresh, isPiStreaming, setPiConnectedPath])

  const currentSessionRef = useRef(currentSession)
  currentSessionRef.current = currentSession

  const handleNewSession = useCallback(async (name: string, parentSessionPath: string) => {
    if (isPiStreaming()) {
      await abort()
    }
    clearMessages()
    const result = await newSession(name, parentSessionPath)
    if (result) {
      await refresh()
      setPiConnectedPath(currentSessionRef.current?.filePath ?? null)
    }
  }, [abort, clearMessages, newSession, refresh, isPiStreaming, setPiConnectedPath])

  const handleForkAtEntry = useCallback(async (entryId: string, name: string) => {
    if (isPiStreaming()) {
      await abort()
    }
    clearMessages()
    await forkAtEntry(entryId, name)
    await loadHistory()
    await refresh()
    setPiConnectedPath(currentSessionRef.current?.filePath ?? null)
  }, [abort, clearMessages, forkAtEntry, loadHistory, refresh, isPiStreaming, setPiConnectedPath])

  const handleForkFromEnd = useCallback(async (sessionPath: string, name: string) => {
    if (isPiStreaming()) {
      await abort()
    }
    const msgs = await getForkMessages()
    const lastEntry = msgs[msgs.length - 1]
    if (!lastEntry?.entryId) return
    clearMessages()
    await forkAtEntry(lastEntry.entryId, name)
    await loadHistory()
    await refresh()
    setPiConnectedPath(currentSessionRef.current?.filePath ?? null)
  }, [abort, getForkMessages, clearMessages, forkAtEntry, loadHistory, refresh, isPiStreaming, setPiConnectedPath])

  const handleClearSession = useCallback(async () => {
    if (isPiStreaming()) {
      await abort()
    }
    clearMessages()
    const ok = await clearSession()
    if (ok) {
      clearMessages()
      await loadHistory()
      await refresh()
      setPiConnectedPath(currentSessionRef.current?.filePath ?? null)
    }
  }, [abort, clearMessages, clearSession, loadHistory, refresh, isPiStreaming, setPiConnectedPath])

  const isLazySwitchedRef = useRef(isLazySwitched)
  isLazySwitchedRef.current = isLazySwitched

  const handleSendPrompt = useCallback(async (text: string, images?: { data: string; mimeType: string }[]) => {
    if (!isLazySwitchedRef.current && isPiStreaming()) return

    if (isLazySwitchedRef.current) {
      const targetPath = displayedSessionPathRef.current
      if (!targetPath) return
      if (isPiStreaming()) await abort()
      const result = await switchSession(targetPath)
      if (result.success) {
        setPiConnectedPath(targetPath)
        clearMessages()
        await loadHistory()
        await loadForkPoints(targetPath)
        await refresh()
        sendPrompt(text, images)
      }
    } else {
      sendPrompt(text, images)
    }
  }, [abort, switchSession, clearMessages, loadHistory, loadForkPoints, refresh, sendPrompt, isPiStreaming, setPiConnectedPath])

  useEffect(() => {
    if (isConnected) {
      const path = currentSessionRef.current?.filePath ?? null
      setPiConnectedPath(path)
      if (path) {
        getOrCreateCacheRef.current(path).then(() => {
          displaySessionRef.current(path).then(() => {
            loadHistory()
          })
        })
      } else {
        loadHistory()
      }
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isConnected, loadHistory])

  useEffect(() => {
    if (isConnected && currentSession?.filePath) {
      loadForkPoints(currentSession.filePath)
    }
  }, [isConnected, currentSession?.filePath, loadForkPoints])

  useEffect(() => {
    setOnAgentEnd(() => () => {
      refresh()
      setIsAgentEnding(true)
      const displayed = displayedSessionPathRef.current
      const currentPiConnected = piConnectedPathRef.current
      if (displayed && displayed !== currentPiConnected) {
        switchSession(displayed).then((result) => {
          if (result.success) {
            setPiConnectedPath(displayed)
            clearMessages()
            loadHistory().then(() => {
              loadForkPoints(displayed)
            })
          }
          setIsAgentEnding(false)
        })
      } else {
        setIsAgentEnding(false)
      }
    })
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [setOnAgentEnd, refresh, switchSession, clearMessages, loadHistory, loadForkPoints, setPiConnectedPath])

  useEffect(() => {
    function handleKeyDown(e: KeyboardEvent): void {
      if (e.key === 'Escape') {
        if (isPiStreaming()) abort()
      }
    }
    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [abort, isPiStreaming])

  useEffect(() => {
    const cleanup = window.api.onEvent((rawEvent) => {
      const evt = rawEvent as { type: string; error?: string; errorMessage?: string }
      if (evt.type === 'extension_error' && evt.error) {
        setError(`Extension error: ${evt.error}`)
      }
    })
    return cleanup
  }, [])

  const projects = sessions?.projects ?? []
  const projectName = projects[0]?.projectPath.split('/').pop() ?? 'Sessions'
  const collapsedSidebarWidth = 48
  const currentSidebarWidth = sidebarCollapsed ? collapsedSidebarWidth : sidebarWidth

  return (
    <div className="flex flex-col h-screen w-screen overflow-hidden bg-white text-gray-900">
      {/* Unified header row split at sidebar width */}
      <div className="flex border-b border-gray-200 bg-gray-50" style={{ WebkitAppRegion: 'drag' } as React.CSSProperties}>
        {/* Left: sidebar header zone */}
        <div
          className="flex items-center justify-between px-3 pt-10 pb-2 flex-shrink-0"
          style={{ width: currentSidebarWidth }}
        >
          <span className="text-xs font-semibold uppercase tracking-wider text-gray-500 truncate">{sidebarCollapsed ? '' : projectName}</span>
          <button
            onClick={() => {
              const next = !sidebarCollapsed
              setSidebarCollapsed(next)
              localStorage.setItem('xi-sidebar-collapsed', String(next))
            }}
            className="rounded p-1 text-gray-500 hover:text-gray-700 hover:bg-gray-100 transition-colors"
            title={sidebarCollapsed ? 'Show sessions' : 'Hide sessions'}
            style={{ WebkitAppRegion: 'no-drag' } as React.CSSProperties}
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
              {sidebarCollapsed ? (
                <path strokeLinecap="round" strokeLinejoin="round" d="M13 5l7 7-7 7M5 5l7 7-7 7" />
              ) : (
                <path strokeLinecap="round" strokeLinejoin="round" d="M11 19l-7-7 7-7M19 19l-7-7 7-7" />
              )}
            </svg>
          </button>
        </div>
        {/* Right: main header zone */}
        <div className="flex items-center justify-between flex-1 px-4 pt-10 pb-2 min-w-0">
          <div className="flex items-center gap-2" style={{ WebkitAppRegion: 'no-drag' } as React.CSSProperties}>
            {activeSessionName && (
              <>
                <span className="text-xs text-gray-700 font-medium">
                  {activeSessionName}
                </span>
                <button
                  onClick={handleClearSession}
                  className="rounded p-1 text-gray-400 hover:text-red-500 hover:bg-gray-100 transition-colors"
                  title="Clear conversation"
                >
                  <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                    <path strokeLinecap="round" strokeLinejoin="round" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                  </svg>
                </button>
              </>
            )}

            {error && (
              <span className="text-xs text-red-500" title={error}>Error</span>
            )}
          </div>
          <div style={{ WebkitAppRegion: 'no-drag' } as React.CSSProperties}>
            <TokenUsageRing
              usedTokens={displayedTokenUsage.totalTokens}
              contextWindowSize={displayedTokenUsage.contextWindowSize}
              inputTokens={displayedTokenUsage.inputTokens}
              outputTokens={displayedTokenUsage.outputTokens}
              cacheReadTokens={displayedTokenUsage.cacheReadTokens}
              totalCost={displayedTokenUsage.totalCost}
            />
          </div>
          <div className="flex items-center rounded-md border border-gray-200 bg-gray-100 p-0.5" style={{ WebkitAppRegion: 'no-drag' } as React.CSSProperties}>
            <button
              onClick={() => { localStorage.setItem('xi-view-mode', 'normal'); setViewMode('normal') }}
              className={`rounded px-2 py-0.5 text-xs font-medium transition-colors ${viewMode === 'normal' ? 'bg-gray-200 text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
              title="Full view"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M3 4h18M3 8h18M3 12h18M3 16h18M3 20h18" />
              </svg>
            </button>
            <button
              onClick={() => { localStorage.setItem('xi-view-mode', 'turn'); setViewMode('turn') }}
              className={`rounded px-2 py-0.5 text-xs font-medium transition-colors ${viewMode === 'turn' ? 'bg-gray-200 text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
              title="Turn view"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M3 5h18M6 9h12M3 13h18M6 17h12" />
              </svg>
            </button>
            <button
              onClick={() => { localStorage.setItem('xi-view-mode', 'outline'); setViewMode('outline') }}
              className={`rounded px-2 py-0.5 text-xs font-medium transition-colors ${viewMode === 'outline' ? 'bg-gray-200 text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
              title="Outline view"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M3 7h18M3 12h18M3 17h18" />
              </svg>
            </button>
          </div>
          <div className="flex items-center gap-2" style={{ WebkitAppRegion: 'no-drag' } as React.CSSProperties}>
            {!isConnected && (
              <button
                onClick={handleConnect}
                className="rounded bg-blue-600 px-3 py-1 text-xs font-medium text-white hover:bg-blue-500"
              >
                Connect to Pi
              </button>
            )}
          </div>
        </div>
      </div>

      {/* Body: sidebar + main content */}
      <div className="flex flex-1 overflow-hidden">
        <SessionSidebar
          sessions={sessions}
          currentSession={currentSession}
          onSwitchSession={handleSwitchSession}
          onNewSession={handleNewSession}
          onRenameSession={renameSession}
          onDeleteSession={deleteSession}
          onSetSessionStatus={setSessionStatus}
          onForkFromEnd={handleForkFromEnd}
          isCollapsed={sidebarCollapsed}
          onToggleCollapse={() => {
            const next = !sidebarCollapsed
            setSidebarCollapsed(next)
            localStorage.setItem('xi-sidebar-collapsed', String(next))
          }}
          width={sidebarWidth}
          onResizeStart={handleResizeStart}
        />

        <div className="flex flex-1 flex-col overflow-hidden">
          {isLazySwitched && (
            <LazySwitchBanner
              backgroundSessionName={backgroundSessionName}
              isAgentEnded={isAgentEnding}
              onStop={abort}
            />
          )}

          <ChatView
            messages={displayedMessages}
            isStreaming={displayedStreaming}
            streamingMessageId={displayedStreamingId}
            pendingUiRequests={pendingUiRequests}
            respondToUiRequest={respondToUiRequest}
            onSendPrompt={handleSendPrompt}
            onForkAtEntry={handleForkAtEntry}
            getForkMessages={getForkMessages}
            forkPoints={displayedForkPoints}
            viewMode={viewMode}
          />

          <InputBar
            onSend={handleSendPrompt}
            disabled={!isConnected}
            isConnected={isConnected}
            isStreaming={displayedStreaming}
            onStop={abort}
          />
        </div>
      </div>
    </div>
  )
}

export default App

import { useState, useEffect, useCallback, useRef, memo } from 'react'
import ReactMarkdown from 'react-markdown'
import remarkGfm from 'remark-gfm'
import type {
  ChatMessage,
  ContentBlock,
  TextBlock,
  ToolCallBlock,
  ToolResultBlock,
  ImageBlock,
  HtmlBlock,
  Annotation,
} from '../types/message'
import type { ForkableMessage, ForkPoint } from '../types/session'
import { ImageAnnotator, annotationsToPrompt } from './ImageAnnotator'
import type { ImageAnnotatorHandle } from './ImageAnnotator'
import type { ViewMode } from '../utils/compact-view'
import { groupByTurns, getUserSummary, getAgentSummary } from '../utils/compact-view'
import type { ConversationTurn } from '../utils/compact-view'

// Slot constants — same as sidebar tree-line-fix for precise alignment
const SLOT_W = 16
const LINE_LEFT = 8
const GRAY = '#e5e7eb'
const BLUE = '#3b82f6'

interface ChatViewProps {
  messages: ChatMessage[]
  isStreaming: boolean
  streamingMessageId: string | null
  onSendPrompt: (text: string, images?: { data: string; mimeType: string }[]) => void
  pendingUiRequests: Array<{ id: string; method: string; [key: string]: unknown }>
  respondToUiRequest: (requestId: string, response: Record<string, unknown>) => void
  onForkAtEntry: (entryId: string, name: string) => void
  getForkMessages: () => Promise<ForkableMessage[]>
  forkPoints: ForkPoint[]
  viewMode: ViewMode
}

function CopyButton({ blocks }: { blocks: ContentBlock[] }): React.ReactElement {
  const [copied, setCopied] = useState(false)

  const handleCopy = useCallback(() => {
    const textParts: string[] = []
    for (const block of blocks) {
      if (block.type === 'text' && !block.subtype) {
        textParts.push(block.content)
      }
    }
    navigator.clipboard.writeText(textParts.join('\n\n')).then(() => {
      setCopied(true)
      setTimeout(() => setCopied(false), 1500)
    })
  }, [blocks])

  return (
    <button
      onClick={handleCopy}
      className="rounded px-2 py-0.5 text-xs text-gray-400 opacity-0 transition-opacity hover:text-gray-600 hover:bg-gray-100 group-hover:opacity-100"
      title="Copy text"
    >
      {copied ? '✓' : 'Copy'}
    </button>
  )
}

function TextBlockRenderer({ block, isStreaming }: { block: TextBlock; isStreaming?: boolean }): React.ReactElement {
  // Thinking content uses its own renderer
  if (block.subtype === 'thinking') {
    return <ThinkingBlockRenderer content={block.content} isStreaming={isStreaming} />
  }

  // During streaming, skip expensive ReactMarkdown parsing to reduce flicker.
  // Use lightweight <pre>-based rendering; switch to full markdown once stable.
  if (isStreaming) {
    return (
      <div className="prose prose-sm max-w-none whitespace-pre-wrap break-words text-sm leading-relaxed">
        {block.content}
        <span className="inline-block w-1.5 h-4 ml-0.5 bg-gray-400 animate-pulse align-text-bottom" />
      </div>
    )
  }
  return (
    <div className="prose prose-sm max-w-none">
      <ReactMarkdown remarkPlugins={[remarkGfm]}>{block.content}</ReactMarkdown>
    </div>
  )
}

function ThinkingBlockRenderer({ content, isStreaming }: { content: string; isStreaming?: boolean }): React.ReactElement {
  const [collapsed, setCollapsed] = useState(true)
  const lineCount = content.split('\n').length
  const firstLine = content.split('\n')[0] || 'Thinking...'

  if (isStreaming) {
    return (
      <div className="py-2 border-l-3 border-purple-300 pl-3">
        <div className="flex items-center gap-2 text-xs font-medium text-purple-600">
          <svg className="h-3.5 w-3.5 animate-spin" viewBox="0 0 24 24" fill="none">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
          </svg>
          Thinking...
        </div>
        <div className="mt-1 whitespace-pre-wrap text-xs italic text-purple-500/80">
          {content}
        </div>
      </div>
    )
  }

  return (
    <div className="py-2 border-l-3 border-purple-300 pl-3">
      <button
        onClick={() => setCollapsed(!collapsed)}
        className="flex w-full items-center gap-2 text-left text-xs font-medium text-purple-600 hover:text-purple-800 transition-colors"
      >
        <svg
          className={`h-3 w-3 transition-transform ${collapsed ? '' : 'rotate-90'}`}
          fill="currentColor"
          viewBox="0 0 20 20"
        >
          <path fillRule="evenodd" d="M7.293 14.707a1 1 0 010-1.414L10.586 10 7.293 6.707a1 1 0 011.414-1.414l4 4a1 1 0 010 1.414l-4 4a1 1 0 01-1.414 0z" clipRule="evenodd" />
        </svg>
        <span>Thinking</span>
        <span className="text-purple-400">({lineCount} line{lineCount !== 1 ? 's' : ''})</span>
      </button>
      {!collapsed && (
        <div className="whitespace-pre-wrap text-xs italic text-purple-700/70 leading-relaxed">
          {content}
        </div>
      )}
      {collapsed && (
        <div className="text-xs italic text-purple-400 truncate">
          {firstLine}
        </div>
      )}
    </div>
  )
}

const COLLAPSE_THRESHOLD = 15

const ToolCallRenderer = memo(function ToolCallRenderer({ block, result }: { block: ToolCallBlock; result?: ToolResultBlock }): React.ReactElement {
  // Always collapsed by default
  const [expanded, setExpanded] = useState(false)

  // Tool-specific header info
  const toolIcon: Record<string, string> = {
    bash: '▶',
    read: '📄',
    edit: '✏️',
    write: '📝',
  }
  const icon = toolIcon[block.toolName] ?? '🔧'

  // Build header summary based on tool type
  let headerSummary = ''
  switch (block.toolName) {
    case 'bash':
      headerSummary = block.args.command
        ? String(block.args.command).length > 80
          ? String(block.args.command).substring(0, 80) + '...'
          : String(block.args.command)
        : ''
      break
    case 'read':
      headerSummary = block.args.path ? String(block.args.path) : ''
      break
    case 'edit':
      headerSummary = block.args.path ? String(block.args.path) : ''
      break
    case 'write':
      headerSummary = block.args.path ? String(block.args.path) : ''
      break
    default:
      headerSummary = ''
  }

  // Status indicator
  const statusEl = (() => {
    switch (block.status) {
      case 'running':
        return (
          <svg className="h-3.5 w-3.5 animate-spin text-yellow-500" viewBox="0 0 24 24" fill="none">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
          </svg>
        )
      case 'completed':
        return <span className="text-green-500 text-xs">✓</span>
      case 'error':
        return <span className="text-red-500 text-xs">✗</span>
      case 'pending':
        return <span className="text-gray-400 text-xs">⋯</span>
    }
  })()

  // Result text content
  const resultText = result
    ? result.content.filter((c): c is TextBlock => c.type === 'text').map((c) => c.content).join('\n')
    : ''
  const resultLines = resultText.split('\n')
  const resultLineCount = resultLines.length
  const resultIsLong = resultLineCount > COLLAPSE_THRESHOLD
  const [outputCollapsed, setOutputCollapsed] = useState(true)
  const displayResult = (outputCollapsed && resultIsLong)
    ? resultLines.slice(0, COLLAPSE_THRESHOLD).join('\n')
    : resultText

  return (
    <div className="py-1 border-t border-gray-200/50 first:border-t-0">
      {/* Header line — always visible */}
      <button
        onClick={() => setExpanded(!expanded)}
        className="flex w-full items-center gap-2 py-1 text-left text-gray-600 hover:text-gray-900 transition-colors"
      >
        <span className="text-xs">{icon}</span>
        <span className="font-mono text-xs font-medium">{block.toolName}</span>
        {headerSummary && (
          <span className="flex-1 truncate font-mono text-xs text-gray-400">{headerSummary}</span>
        )}
        {!headerSummary && <span className="flex-1" />}
        {statusEl}
        <svg
          className={`h-3 w-3 text-gray-300 transition-transform ${expanded ? 'rotate-90' : ''}`}
          fill="currentColor"
          viewBox="0 0 20 20"
        >
          <path fillRule="evenodd" d="M7.293 14.707a1 1 0 010-1.414L10.586 10 7.293 6.707a1 1 0 011.414-1.414l4 4a1 1 0 010 1.414l-4 4a1 1 0 01-1.414 0z" clipRule="evenodd" />
        </svg>
      </button>
      {/* Expandable details */}
      {expanded && (
        <div className="ml-4 border-l-2 border-gray-200 pl-3 py-1">
          {/* Args */}
          <pre className="overflow-x-auto text-xs text-gray-500">
            {JSON.stringify(block.args, null, 2)}
          </pre>
          {/* Output */}
          {resultText.trim().length > 0 && (
            <div className="mt-1">
              <div className="flex items-center justify-between py-0.5">
                <span className="text-xs text-gray-400">
                  Output{resultLineCount > 1 ? ` (${resultLineCount} lines)` : ''}
                </span>
                {resultIsLong && (
                  <button
                    onClick={(e) => { e.stopPropagation(); setOutputCollapsed(!outputCollapsed) }}
                    className="text-xs text-blue-500 hover:underline"
                  >
                    {outputCollapsed ? `Show all ${resultLineCount} lines` : 'Collapse'}
                  </button>
                )}
              </div>
              <pre className="whitespace-pre-wrap text-xs font-mono text-gray-500">
                {displayResult}
              </pre>
              {outputCollapsed && resultIsLong && (
                <div className="text-center">
                  <button
                    onClick={(e) => { e.stopPropagation(); setOutputCollapsed(false) }}
                    className="text-xs text-blue-500 hover:underline"
                  >
                    ▸ Show all {resultLineCount} lines
                  </button>
                </div>
              )}
            </div>
          )}
          {/* Non-text result content (images, html) */}
          {result && result.content.map((child, i) => {
            if (child.type === 'image') {
              return <ImageBlockRenderer key={`img-${i}`} block={child as ImageBlock} />
            }
            if (child.type === 'html') {
              return <HtmlBlockRenderer key={`html-${i}`} block={child as HtmlBlock} />
            }
            return null
          })}
        </div>
      )}
    </div>
  )
})

function HtmlBlockRenderer({ block }: { block: HtmlBlock }): React.ReactElement {
  const [expanded, setExpanded] = useState(true)
  const iframeRef = useRef<HTMLIFrameElement>(null)

  const handleLoad = useCallback(() => {
    if (!iframeRef.current) return
    const doc = iframeRef.current.contentDocument
    if (!doc?.body) return
    const height = doc.body.scrollHeight
    iframeRef.current.style.height = `${Math.min(Math.max(height, 100), 600)}px`
  }, [])

  return (
    <div className="my-2 overflow-hidden rounded border border-gray-200">
      <div className="flex items-center justify-between bg-gray-100 px-3 py-1.5">
        <span className="text-xs font-medium text-gray-500">
          {block.title ?? 'HTML Preview'}
        </span>
        <button
          onClick={() => setExpanded(!expanded)}
          className="text-xs text-gray-400 hover:text-gray-600"
        >
          {expanded ? 'Collapse' : 'Expand'}
        </button>
      </div>
      {expanded && (
        <iframe
          ref={iframeRef}
          srcDoc={block.content}
          sandbox="allow-scripts allow-same-origin"
          onLoad={handleLoad}
          className="w-full border-0 bg-white"
          style={{ height: '300px' }}
          title={block.title ?? 'HTML Preview'}
        />
      )}
    </div>
  )
}

interface AnnotatableImageBlockProps {
  block: ImageBlock
  messageId: string
  blockIndex: number
  isAnnotating: boolean
  onEnterAnnotation: () => void
  onExitAnnotation: () => void
  onSendFeedback: (description: string, imageData: string) => void
}

function AnnotatableImageBlock({
  block,
  messageId,
  blockIndex,
  isAnnotating,
  onEnterAnnotation,
  onExitAnnotation,
  onSendFeedback,
}: AnnotatableImageBlockProps): React.ReactElement {
  const [annotations, setAnnotations] = useState<Annotation[]>([])
  const [isFullscreen, setIsFullscreen] = useState(false)
  const [zoom, setZoom] = useState(1)
  const annotatorRef = useRef<ImageAnnotatorHandle>(null)

  void messageId
  void blockIndex

  const handleWheel = useCallback((e: React.WheelEvent) => {
    e.preventDefault()
    setZoom((prev) => Math.max(0.25, Math.min(4, prev + (e.deltaY > 0 ? -0.15 : 0.15))))
  }, [])

  useEffect(() => {
    if (!isFullscreen) return
    const handler = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        setIsFullscreen(false)
        setZoom(1)
      }
    }
    window.addEventListener('keydown', handler)
    return () => window.removeEventListener('keydown', handler)
  }, [isFullscreen])

  const handleSendFeedback = useCallback(() => {
    if (!annotatorRef.current) return
    const result = annotatorRef.current.getAnnotatedImage()
    if (!result) return

    const base64Match = result.dataUrl.match(/^data:image\/png;base64,(.+)$/)
    if (!base64Match) return

    onSendFeedback(result.description, base64Match[1])
    onExitAnnotation()
  }, [onSendFeedback, onExitAnnotation])

  if (isAnnotating) {
    return (
      <div className="my-2 overflow-hidden rounded border border-blue-600">
        <ImageAnnotator
          ref={annotatorRef}
          src={block.src}
          alt={block.alt}
          annotations={annotations}
          onAnnotationsChange={setAnnotations}
          isActive={true}
        />
        <div className="flex items-center justify-between border-t border-blue-600 bg-gray-100 px-3 py-2">
          <span className="text-xs text-gray-600">
            {annotations.length} annotation{annotations.length !== 1 ? 's' : ''}
          </span>
          <div className="flex gap-2">
            <button
              onClick={onExitAnnotation}
              className="rounded bg-gray-200 px-3 py-1 text-xs font-medium text-gray-700 hover:bg-gray-300"
            >
              Cancel
            </button>
            <button
              onClick={handleSendFeedback}
              className="rounded bg-blue-600 px-3 py-1 text-xs font-medium text-white hover:bg-blue-500"
            >
              Send Feedback
            </button>
          </div>
        </div>
      </div>
    )
  }

  if (isFullscreen) {
    return (
      <div
        className="fixed inset-0 z-50 flex items-center justify-center bg-black/50"
        onClick={() => {
          setIsFullscreen(false)
          setZoom(1)
        }}
      >
        <img
          src={block.src}
          alt={block.alt ?? 'image'}
          style={{ transform: `scale(${zoom})`, transformOrigin: 'center' }}
          className="max-h-[90vh] max-w-[90vw] cursor-zoom-out transition-transform"
          onWheel={handleWheel}
          onClick={(e) => e.stopPropagation()}
        />
        <div className="absolute bottom-4 right-4 flex gap-2">
          <button
            onClick={(e) => {
              e.stopPropagation()
              setZoom((z) => Math.min(4, z + 0.25))
            }}
            className="rounded bg-gray-800/80 px-3 py-1 text-sm text-white hover:bg-gray-700"
          >
            +
          </button>
          <span className="rounded bg-gray-800/80 px-3 py-1 text-sm text-white">
            {Math.round(zoom * 100)}%
          </span>
          <button
            onClick={(e) => {
              e.stopPropagation()
              setZoom((z) => Math.max(0.25, z - 0.25))
            }}
            className="rounded bg-gray-800/80 px-3 py-1 text-sm text-white hover:bg-gray-700"
          >
            -
          </button>
          <button
            onClick={(e) => {
              e.stopPropagation()
              setIsFullscreen(false)
              setZoom(1)
            }}
            className="rounded bg-red-800/80 px-3 py-1 text-sm text-white hover:bg-red-700"
          >
            ESC
          </button>
        </div>
      </div>
    )
  }

  return (
    <div className="my-2 overflow-hidden rounded border border-gray-200">
      <div className="relative group">
        <img
          src={block.src}
          alt={block.alt ?? 'image'}
          className="max-w-full cursor-zoom-in transition-opacity hover:opacity-90"
          onClick={() => setIsFullscreen(true)}
          loading="lazy"
        />
        <button
          onClick={onEnterAnnotation}
          className="absolute top-2 right-2 rounded bg-blue-600/90 px-2 py-1 text-xs font-medium text-white opacity-0 transition-opacity hover:bg-blue-500 group-hover:opacity-100"
        >
          Annotate
        </button>
      </div>
      {block.alt && (
        <div className="border-t border-gray-200 bg-gray-50 px-2 py-1 text-xs text-gray-500">
          {block.alt}
        </div>
      )}
    </div>
  )
}

/**
 * Render blocks from multiple merged messages as one unit.
 * Collects all tool_call/tool_result pairs across messages into one group.
 */
function MergedBlocksRenderer({
  messages,
  isStreaming,
  streamingMessageId,
  annotatingTarget,
  onEnterAnnotation,
  onExitAnnotation,
  onSendFeedback,
}: {
  messages: ChatMessage[]
  isStreaming: boolean
  streamingMessageId: string | null
  annotatingTarget: { messageId: string; blockIndex: number } | null
  onEnterAnnotation: (messageId: string, blockIndex: number) => void
  onExitAnnotation: () => void
  onSendFeedback: (description: string, imageData: string) => void
}): React.ReactElement {
  // Flatten all blocks, track which message each came from
  const allBlocks: { block: ContentBlock; msgId: string; blockIdx: number }[] = []
  for (const msg of messages) {
    msg.blocks.forEach((block, idx) => {
      allBlocks.push({ block, msgId: msg.id, blockIdx: idx })
    })
  }

  // Identify paired tool_result indices (right after their tool_call)
  const pairedResultIndices = new Set<number>()
  for (let j = 0; j < allBlocks.length; j++) {
    if (allBlocks[j].block.type === 'tool_call' && allBlocks[j + 1]?.block.type === 'tool_result') {
      pairedResultIndices.add(j + 1)
    }
  }

  // Render blocks in original order
  const elements: React.ReactElement[] = []

  for (let j = 0; j < allBlocks.length; j++) {
    const { block, msgId, blockIdx } = allBlocks[j]

    // Skip paired tool_result (will be rendered inside its tool_call)
    if (pairedResultIndices.has(j)) continue

    if (block.type === 'tool_call') {
      const result = allBlocks[j + 1]?.block.type === 'tool_result' ? allBlocks[j + 1].block as ToolResultBlock : undefined
      elements.push(
        <ToolCallRenderer key={`tc-${j}`} block={block} result={result} />
      )
      continue
    }

    if (block.type === 'tool_result') {
      // Orphan tool_result
      elements.push(
        <OrphanToolResultRenderer key={`tr-${j}`} block={block} />
      )
      continue
    }

    elements.push(
      <ContentBlockRenderer
        key={`cb-${j}`}
        block={block}
        messageId={msgId}
        blockIndex={blockIdx}
        isStreamingBlock={isStreaming && streamingMessageId === msgId && block.type === 'text'}
        annotatingTarget={annotatingTarget}
        onEnterAnnotation={onEnterAnnotation}
        onExitAnnotation={onExitAnnotation}
        onSendFeedback={onSendFeedback}
      />
    )
  }

  return <div className="space-y-3">{elements}</div>
}

/**
 * Render all blocks of a single message.
 * Collects all tool_call/tool_result pairs from the message into one card.
 * Other blocks render normally in order.
 */
function MessageBlocksRenderer({
  msg,
  isStreaming,
  streamingMessageId,
  annotatingTarget,
  onEnterAnnotation,
  onExitAnnotation,
  onSendFeedback,
}: {
  msg: ChatMessage
  isStreaming: boolean
  streamingMessageId: string | null
  annotatingTarget: { messageId: string; blockIndex: number } | null
  onEnterAnnotation: (messageId: string, blockIndex: number) => void
  onExitAnnotation: () => void
  onSendFeedback: (description: string, imageData: string) => void
}): React.ReactElement {
  // Identify paired tool_result indices (right after their tool_call)
  const pairedResultIndices = new Set<number>()
  for (let j = 0; j < msg.blocks.length; j++) {
    if (msg.blocks[j].type === 'tool_call' && msg.blocks[j + 1]?.type === 'tool_result') {
      pairedResultIndices.add(j + 1)
    }
  }

  // Render blocks in original order
  const elements: React.ReactElement[] = []

  for (let j = 0; j < msg.blocks.length; j++) {
    const block = msg.blocks[j]

    // Skip paired tool_result (will be rendered inside its tool_call)
    if (pairedResultIndices.has(j)) continue

    if (block.type === 'tool_call') {
      const result = msg.blocks[j + 1]?.type === 'tool_result' ? msg.blocks[j + 1] as ToolResultBlock : undefined
      elements.push(
        <ToolCallRenderer key={`tc-${j}`} block={block} result={result} />
      )
      continue
    }

    if (block.type === 'tool_result') {
      // Orphan tool_result
      elements.push(
        <OrphanToolResultRenderer key={`tr-${j}`} block={block} />
      )
      continue
    }

    elements.push(
      <ContentBlockRenderer
        key={`cb-${j}`}
        block={block}
        messageId={msg.id}
        blockIndex={j}
        isStreamingBlock={isStreaming && streamingMessageId === msg.id && block.type === 'text'}
        annotatingTarget={annotatingTarget}
        onEnterAnnotation={onEnterAnnotation}
        onExitAnnotation={onExitAnnotation}
        onSendFeedback={onSendFeedback}
      />
    )
  }

  return <div className="space-y-3">{elements}</div>
}

/** Render a tool_result that has no matching tool_call (rare edge case) */
function OrphanToolResultRenderer({ block }: { block: ToolResultBlock }): React.ReactElement {
  const textItems = block.content.filter((c): c is TextBlock => c.type === 'text')
  const fullText = textItems.map((c) => c.content).join('\n')
  return (
    <div className="my-1 rounded-lg border border-gray-200 bg-gray-50 px-3 py-2 overflow-x-auto">
      <pre className="whitespace-pre-wrap text-xs font-mono text-gray-600">{fullText}</pre>
    </div>
  )
}

const ContentBlockRenderer = memo(function ContentBlockRenderer({
  block,
  messageId,
  blockIndex,
  isStreamingBlock,
  annotatingTarget,
  onEnterAnnotation,
  onExitAnnotation,
  onSendFeedback,
}: {
  block: ContentBlock
  messageId: string
  blockIndex: number
  isStreamingBlock?: boolean
  annotatingTarget: { messageId: string; blockIndex: number } | null
  onEnterAnnotation: (messageId: string, blockIndex: number) => void
  onExitAnnotation: () => void
  onSendFeedback: (description: string, imageData: string) => void
}): React.ReactElement | null {
  switch (block.type) {
    case 'text':
      return <TextBlockRenderer block={block} isStreaming={isStreamingBlock} />
    case 'image':
      return (
        <AnnotatableImageBlock
          block={block}
          messageId={messageId}
          blockIndex={blockIndex}
          isAnnotating={
            annotatingTarget !== null &&
            annotatingTarget.messageId === messageId &&
            annotatingTarget.blockIndex === blockIndex
          }
          onEnterAnnotation={() => onEnterAnnotation(messageId, blockIndex)}
          onExitAnnotation={onExitAnnotation}
          onSendFeedback={onSendFeedback}
        />
      )
    case 'action':
      return <div className="text-xs text-yellow-600">[Action: {block.actionType}]</div>
    case 'html':
      return <HtmlBlockRenderer block={block} />
    default:
      return null
  }
})

function ForkNameInput({
  onForkAtEntry,
  onClose,
  defaultEntryId,
}: {
  onForkAtEntry: (entryId: string, name: string) => void
  onClose: () => void
  defaultEntryId: string
}): React.ReactElement {
  const popoverRef = useRef<HTMLDivElement>(null)
  const [forkName, setForkName] = useState('')

  useEffect(() => {
    function handleClickOutside(e: MouseEvent): void {
      if (popoverRef.current && !popoverRef.current.contains(e.target as Node)) {
        onClose()
      }
    }
    document.addEventListener('mousedown', handleClickOutside)
    return () => document.removeEventListener('mousedown', handleClickOutside)
  }, [onClose])

  const handleConfirm = useCallback(() => {
    if (forkName.trim()) {
      onForkAtEntry(defaultEntryId, forkName.trim())
      onClose()
    }
  }, [forkName, defaultEntryId, onForkAtEntry, onClose])

  return (
    <div
      ref={popoverRef}
      className="absolute right-0 top-8 z-30 w-64 rounded-lg border border-gray-200 bg-white shadow-xl"
    >
      <div className="px-3 py-2 space-y-1.5">
        <input
          autoFocus
          value={forkName}
          onChange={(e) => setForkName(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === 'Enter') handleConfirm()
            if (e.key === 'Escape') onClose()
          }}
          placeholder="Fork session name"
          className="w-full rounded border border-gray-300 bg-white px-2 py-1 text-xs text-gray-900 outline-none focus:border-blue-500"
        />
        <button
          onClick={handleConfirm}
          disabled={!forkName.trim()}
          className="w-full rounded bg-blue-600 px-2 py-1 text-xs font-medium text-white hover:bg-blue-500 disabled:opacity-40 disabled:cursor-not-allowed"
        >
          Fork from here
        </button>
      </div>
    </div>
  )
}

function TurnDotSlot({ active, isFirst, isLast, isCollapsed, onClick }: {
  active: boolean
  isFirst: boolean
  isLast: boolean
  isCollapsed?: boolean
  onClick?: () => void
}) {
  const borderColor = active ? BLUE : GRAY
  return (
    <div
      className={`flex-shrink-0 relative${isCollapsed ? ' cursor-pointer' : ''}`}
      style={{ width: SLOT_W, alignSelf: 'stretch' }}
      onClick={isCollapsed ? onClick : undefined}
    >
      {/* Line above dot — from top to dot center (only if not first) */}
      {!isFirst && (
        <div
          className="absolute"
          style={{ left: LINE_LEFT, top: 0, height: 'calc(50% - 5px)', width: 1.5, backgroundColor: GRAY }}
        />
      )}
      {/* Dot */}
      <div
        className={isCollapsed ? 'transition-colors' : undefined}
        style={{
          left: LINE_LEFT - 5,
          top: 'calc(50% - 5px)',
          width: 10,
          height: 10,
          borderRadius: '50%',
          backgroundColor: active ? BLUE : 'white',
          border: `2px solid ${borderColor}`,
          position: 'absolute',
          ...(isCollapsed ? { cursor: 'pointer' } : {}),
        }}
        onMouseEnter={isCollapsed ? (e) => { (e.currentTarget as HTMLElement).style.borderColor = BLUE } : undefined}
        onMouseLeave={isCollapsed ? (e) => { (e.currentTarget as HTMLElement).style.borderColor = borderColor } : undefined}
      />
      {/* Line below dot — from dot center to bottom (only if not last) */}
      {!isLast && (
        <div
          className="absolute"
          style={{ left: LINE_LEFT, top: 'calc(50% + 5px)', bottom: 0, width: 1.5, backgroundColor: GRAY }}
        />
      )}
    </div>
  )
}

/**
 * Expanded content with a blue left border aligned to the dot center.
 * Uses a wrapper with padding-left=SLOT_W so the border at left=LINE_LEFT (8px)
 * visually aligns with the dot center in the gutter slot.
 */
function ExpandedContent({ children }: { children: React.ReactNode }) {
  return (
    <div className="relative flex-1 min-w-0 overflow-visible">
      {/* Blue left border aligned to dot center at LINE_LEFT */}
      <div
        className="absolute"
        style={{
          left: LINE_LEFT - SLOT_W,
          top: 0,
          bottom: 0,
          width: 3,
          backgroundColor: BLUE,
          borderRadius: '2px 0 0 2px',
        }}
      />
      <div className="bg-blue-50/30 rounded-r-lg">
        {children}
      </div>
    </div>
  )
}

function TurnCard({
  turn,
  isFirst,
  isLast,
  isExpanded,
  onToggleExpand,
  annotatingTarget,
  onEnterAnnotation,
  onExitAnnotation,
  onSendFeedback,
  onForkClick,
  forkInputMessageId,
  forkEntryId,
  onForkClose,
  onForkAtEntry,
  forkPoints,
  isStreaming,
  streamingMessageId,
}: {
  turn: ConversationTurn
  isFirst: boolean
  isLast: boolean
  isExpanded: boolean
  onToggleExpand: () => void
  annotatingTarget: { messageId: string; blockIndex: number } | null
  onEnterAnnotation: (messageId: string, blockIndex: number) => void
  onExitAnnotation: () => void
  onSendFeedback: (description: string, imageData: string) => void
  onForkClick: (messageId: string, piEntryId: string | undefined) => void
  forkInputMessageId: string | null
  forkEntryId: string | null
  onForkClose: () => void
  onForkAtEntry: (entryId: string, name: string) => void
  forkPoints: ForkPoint[]
  isStreaming: boolean
  streamingMessageId: string | null
}): React.ReactElement {
  const userSummary = getUserSummary(turn.userMessage)
  const agentSummary = getAgentSummary(turn.assistantMessages)

  if (isExpanded) {
    const allMessages = [turn.userMessage, ...turn.assistantMessages]
    return (
      <div className="flex">
        <TurnDotSlot active={true} isFirst={isFirst} isLast={isLast} />
        <ExpandedContent>
          <div className="flex items-center justify-end px-3 py-1">
            <button
              onClick={onToggleExpand}
              className="rounded px-2 py-0.5 text-xs text-gray-500 hover:text-gray-700 hover:bg-gray-100 transition-colors"
            >
              Collapse
            </button>
          </div>
          <div className="space-y-4 px-4 pb-4">
            {allMessages.map((msg) => {
              const msgForkPoints = forkPoints.filter((fp) => fp.entryId === msg.piEntryId)
              return (
                <div
                  key={msg.id}
                  className={`group relative rounded-lg px-4 py-3 ${
                    msg.role === 'user' ? 'bg-blue-50' : 'bg-gray-50'
                  }`}
                >
                  <div className="mb-1 flex items-center justify-between">
                    <span className="text-xs font-medium text-gray-500">
                      {msg.role === 'user' ? 'You' : 'Pi'}
                    </span>
                    <div className="relative">
                      <button
                        onClick={() => onForkClick(msg.id, msg.piEntryId)}
                        className="rounded px-2 py-0.5 text-xs text-gray-400 opacity-0 transition-opacity hover:text-gray-600 hover:bg-gray-100 group-hover:opacity-100"
                      >
                        Fork
                      </button>
                      {forkInputMessageId === msg.id && forkEntryId && (
                        <ForkNameInput
                          onForkAtEntry={onForkAtEntry}
                          onClose={onForkClose}
                          defaultEntryId={forkEntryId}
                        />
                      )}
                    </div>
                  </div>
                  <MessageBlocksRenderer
                    msg={msg}
                    isStreaming={isStreaming}
                    streamingMessageId={streamingMessageId}
                    annotatingTarget={annotatingTarget}
                    onEnterAnnotation={onEnterAnnotation}
                    onExitAnnotation={onExitAnnotation}
                    onSendFeedback={onSendFeedback}
                  />
                  {msgForkPoints.length > 0 && (
                    <div className="mt-2 flex flex-wrap gap-1.5 border-t border-gray-200/50 pt-2">
                      {msgForkPoints.map((fp, idx) => (
                        <span
                          key={idx}
                          className="inline-flex items-center gap-1 rounded-full bg-purple-100 px-2 py-0.5 text-[10px] text-purple-700"
                        >
                          <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                            <path strokeLinecap="round" strokeLinejoin="round" d="M13 17h8m0 0V9m0 8l-8-8-4 4-6-6" />
                          </svg>
                          forked: {fp.childName || '(unnamed)'}
                        </span>
                      ))}
                    </div>
                  )}
                </div>
              )
            })}
          </div>
        </ExpandedContent>
      </div>
    )
  }

  return (
    <div className="flex">
      <TurnDotSlot active={false} isFirst={isFirst} isLast={isLast} isCollapsed onClick={onToggleExpand} />
      <div
        className="flex-1 cursor-pointer rounded-lg border border-gray-200 bg-white px-4 py-2.5 hover:bg-gray-50 transition-colors ml-1"
