import { useState, useRef, useCallback } from 'react'

interface InputBarProps {
  onSend: (text: string, images?: { data: string; mimeType: string }[]) => void
  disabled: boolean
  isConnected: boolean
  isStreaming?: boolean
  onStop?: () => void
  isLazySwitched?: boolean
  backgroundSessionName?: string | null
  isAgentEnding?: boolean
}

function InputBar({ onSend, disabled, isConnected, isStreaming, onStop, isLazySwitched, backgroundSessionName, isAgentEnding }: InputBarProps): React.ReactElement {
  const [text, setText] = useState('')
  const [pastedImages, setPastedImages] = useState<{ data: string; mimeType: string }[]>([])
  const textareaRef = useRef<HTMLTextAreaElement>(null)

  const showStop = isStreaming || (isLazySwitched && !isAgentEnding)

  const handleSubmit = useCallback((): void => {
    const trimmed = text.trim()
    if (!trimmed && pastedImages.length === 0) return
    if (disabled) return
    onSend(trimmed, pastedImages.length > 0 ? pastedImages : undefined)
    setText('')
    setPastedImages([])
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto'
    }
  }, [text, pastedImages, disabled, onSend])

  function handleKeyDown(e: React.KeyboardEvent<HTMLTextAreaElement>): void {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()
      handleSubmit()
    }
  }

  function handleInput(e: React.ChangeEvent<HTMLTextAreaElement>): void {
    setText(e.target.value)
    const el = e.target
    el.style.height = 'auto'
    el.style.height = Math.min(el.scrollHeight, 96) + 'px'
  }

  function handlePaste(e: React.ClipboardEvent): void {
    const items = e.clipboardData.items
    for (const item of items) {
      if (item.type.startsWith('image/')) {
        e.preventDefault()
        const blob = item.getAsFile()
        if (!blob) continue
        const reader = new FileReader()
        reader.onload = () => {
          const result = reader.result as string
          const match = result.match(/^data:(image\/\w+);base64,(.+)$/)
          if (match) {
            setPastedImages((prev) => [...prev, { mimeType: match[1], data: match[2] }])
          }
        }
        reader.readAsDataURL(blob)
      }
    }
  }

  // Merged status line: lazy switch info integrated into Pi Connected status
  let statusDot: React.ReactNode
  let statusText: React.ReactNode

  if (isAgentEnding) {
    statusDot = <svg className="h-2 w-2 animate-spin text-blue-500" viewBox="0 0 24 24" fill="none"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" /><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" /></svg>
    statusText = <span className="text-blue-600">Switching back…</span>
  } else if (isLazySwitched && backgroundSessionName) {
    statusDot = (
      <span className="relative flex h-1.5 w-1.5">
        <span className="absolute inline-flex h-full w-full animate-ping rounded-full bg-blue-400 opacity-75" />
        <span className="relative inline-flex h-1.5 w-1.5 rounded-full bg-blue-500" />
      </span>
    )
    statusText = <span className="text-blue-600">{backgroundSessionName} running</span>
  } else if (isStreaming) {
    statusDot = <span className="inline-block h-1.5 w-1.5 rounded-full bg-blue-500 animate-pulse" />
    statusText = <>Pi is thinking… press <kbd className="rounded border border-gray-200 bg-gray-100 px-1 py-px font-mono text-[10px] leading-none text-gray-500">Esc</kbd> to interrupt</>
  } else {
    statusDot = <span className={`inline-block h-1.5 w-1.5 rounded-full ${isConnected ? 'bg-green-500' : 'bg-red-500'}`} />
    statusText = isConnected ? 'Pi Connected' : 'Pi Disconnected'
  }

  return (
    <div className="border-t border-gray-200 bg-white px-4 py-3">
      <div className="mb-2 flex items-center gap-1.5 text-xs text-gray-400">
        {statusDot}
        {statusText}
      </div>
      {pastedImages.length > 0 && (
        <div className="mb-2 flex gap-2">
          {pastedImages.map((img, i) => (
            <div key={i} className="relative">
              <img
                src={`data:${img.mimeType};base64,${img.data}`}
                alt="pasted"
                className="h-16 rounded border border-gray-200"
              />
              <button
                onClick={() => setPastedImages((prev) => prev.filter((_, j) => j !== i))}
                className="absolute -right-1 -top-1 flex h-4 w-4 items-center justify-center rounded-full bg-red-600 text-[10px] text-white"
              >
                ×
              </button>
            </div>
          ))}
        </div>
      )}
      <div className="flex items-end gap-2">
        <textarea
          ref={textareaRef}
          value={text}
          onChange={handleInput}
          onKeyDown={handleKeyDown}
          onPaste={handlePaste}
          disabled={disabled}
          rows={1}
          placeholder={disabled ? 'Pi not connected...' : 'Type a message... (paste images with Ctrl+V)'}
          className="flex-1 resize-none rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm text-gray-900 placeholder-gray-400 focus:outline-none focus:ring-1 focus:ring-gray-300 disabled:opacity-50"
        />
        {showStop ? (
          <button
            onClick={onStop}
            className="rounded-lg bg-red-600 px-4 py-2 text-sm font-medium text-white transition-colors hover:bg-red-500"
          >
            Stop
          </button>
        ) : (
          <button
            onClick={handleSubmit}
            disabled={disabled || (!text.trim() && pastedImages.length === 0)}
            className="rounded-lg bg-blue-600 px-4 py-2 text-sm font-medium text-white transition-colors hover:bg-blue-500 disabled:opacity-50 disabled:hover:bg-blue-600"
          >
            Send
          </button>
        )}
      </div>
    </div>
  )
}

export default InputBar

